import{_ as t,C as d,o as p,c as i,a2 as s,j as o,a as e,E as l,w as n}from"./chunks/framework.N6Nd-M9-.js";const v=JSON.parse('{"title":"企业精神","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/新人手册/02-企业精神.md","filePath":"notes/企业文化/新人手册/02-企业精神.md"}'),g={name:"notes/企业文化/新人手册/02-企业精神.md"};function c(x,r,b,y,u,m){const a=d("font");return p(),i("div",null,[r[2]||(r[2]=s('<h1 id="企业精神" tabindex="-1">企业精神 <a class="header-anchor" href="#企业精神" aria-label="Permalink to &quot;企业精神&quot;">​</a></h1><blockquote><p>企业精神是我们共同的价值追求和行为准则，指引着每一位员工的工作方向和职业态度。 💡 我们的企业精神：**务实、进取、协作...</p></blockquote><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">💡 核心要点</p><p class="tc-body">企业精神是我们共同的价值追求和行为准则，指引着每一位员工的工作方向和职业态度。 💡 我们的企业精神：**务实、进取、协作...</p></div><hr><h2 id="🚀-同创梦" tabindex="-1">🚀 同创梦 <a class="header-anchor" href="#🚀-同创梦" aria-label="Permalink to &quot;🚀 同创梦&quot;">​</a></h2>',5)),o("p",null,[r[1]||(r[1]=e("  ",-1)),l(a,{color:"#667eea"},{default:n(()=>[...r[0]||(r[0]=[e("中国梦是中华民族数千年渴望与理想的集合，同创梦是每个同创人对美好生活具体想象的汇聚。",-1)])]),_:1})]),r[3]||(r[3]=s('<p>  在这里，更多的人有稳定可发展的工作机会；员工的付出得到非常好的回报，有越来越满意的收入；拥有自己的娱乐中心，员工工作之余精神生活丰富多彩；拥有自己的婚姻服务机构，为员工寻找伴侣牵线搭桥；拥有自己的住宅区，员工享有更舒适的居住条件和更优美的居住环境；拥有自己的学校，让我们的孩子无忧无虑的健康成长；年轻人进入我们的商学院，得到更好的教育；夫妻情侣得到美满的家庭；老人们找到共同的兴趣爱好及伙伴，其乐融融；我们还拥有自己的医院，员工享受高水平的免费的医疗卫生服务；拥有自己的老年康复中心，员工老有所养，安度晚年……这就是同创梦！</p><h2 id="📌-juice" tabindex="-1">📌 JUICE <a class="header-anchor" href="#📌-juice" aria-label="Permalink to &quot;📌 JUICE&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px;margin:15px 0;"><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold tc-center" style="margin:0;font-size:16px;">🤝 让我们一起参与公司发展</p></div><div style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:18px;border-radius:12px;"><p class="tc-green tc-bold tc-center" style="margin:0;font-size:16px;">🎉 让我们一起创造兴奋的气氛</p></div><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:18px;border-radius:12px;"><p class="tc-bold tc-center" style="margin:0;font-size:16px;color:#f97316;">🚀 让我们一起创造企业家</p></div><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold tc-center" style="margin:0;font-size:16px;">🏆 让我们一起庆祝发展与成功</p></div></div><h2 id="🏛️-集团口号" tabindex="-1">🏛️ 集团口号 <a class="header-anchor" href="#🏛️-集团口号" aria-label="Permalink to &quot;🏛️ 集团口号&quot;">​</a></h2><p>  企业口号是企业文化与企业精神的融合，它指导着我们的思想与行为，使我们产生一致的目标，诞生一致的梦想，产生一致的激情。</p><div class="tc-center" style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:16px;margin:20px 0;"><p class="tc-blue tc-bold" style="font-size:32px;margin:0 0 20px 0;">📣 同创同创，共同创造！</p><div style="display:flex;flex-wrap:wrap;justify-content:center;gap:15px;"><div style="background:rgba(102,126,234,0.08);padding:15px 20px;border-radius:12px;max-width:400px;"><p class="tc-body" style="margin:0;font-size:16px;">第一个<strong>&quot;同创&quot;</strong>，是指同创人。</p></div><div style="background:rgba(102,126,234,0.08);padding:15px 20px;border-radius:12px;max-width:400px;"><p class="tc-body" style="margin:0;font-size:16px;">第二个<strong>&quot;同创&quot;</strong>，是指同创梦。</p></div></div><p class="tc-body" style="margin:20px 0 0 0;font-size:15px;">因为有一致的身份定义，才会一起去创造和每个人都相关的美好生活。</p></div><h2 id="🌟-愿景" tabindex="-1">🌟 愿景 <a class="header-anchor" href="#🌟-愿景" aria-label="Permalink to &quot;🌟 愿景&quot;">​</a></h2><div class="tc-center" style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:25px;border-radius:16px;margin:20px 0;"><p class="tc-green tc-bold" style="font-size:28px;margin:0;font-family:Cursive;">🌟 中国最佳创业联盟，员工幸福指数最高</p></div><h2 id="🚀-使命" tabindex="-1">🚀 使命 <a class="header-anchor" href="#🚀-使命" aria-label="Permalink to &quot;🚀 使命&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin:15px 0;"><div class="tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">🎯</p><p class="tc-blue tc-bold" style="font-size:18px;margin:0;">成就顾客</p></div><div class="tc-center" style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">🤝</p><p class="tc-green tc-bold" style="font-size:18px;margin:0;">成就伙伴</p></div><div class="tc-center" style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">💪</p><p class="tc-bold" style="font-size:18px;margin:0;color:#f97316;">成就自己</p></div><div class="tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">👨‍👩‍👧‍👦</p><p class="tc-blue tc-bold" style="font-size:18px;margin:0;">成就家人</p></div><div class="tc-center" style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">🌍</p><p class="tc-green tc-bold" style="font-size:18px;margin:0;">成就社会</p></div></div><h2 id="🎯-核心价值观" tabindex="-1">🎯 核心价值观 <a class="header-anchor" href="#🎯-核心价值观" aria-label="Permalink to &quot;🎯 核心价值观&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px;margin:15px 0;"><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold" style="margin:0;font-size:16px;">💎 诚信</p><p class="tc-body" style="margin:8px 0 0 0;font-size:14px;">忠诚正直、信守承诺</p></div><div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);padding:18px;border-radius:12px;"><p class="tc-red tc-bold" style="margin:0;font-size:16px;">❤️ 爱人如己</p><p class="tc-body" style="margin:8px 0 0 0;font-size:14px;">关爱别人像对待自己一样。</p></div><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:18px;border-radius:12px;"><p class="tc-bold" style="margin:0;font-size:16px;color:#f97316;">🔥 尽己所能</p><p class="tc-body" style="margin:8px 0 0 0;font-size:14px;">尽心、尽意、尽力、尽性</p></div><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold" style="margin:0;font-size:16px;">🚀 追求卓越</p><p class="tc-body" style="margin:8px 0 0 0;font-size:14px;">突破自我、不断改变、不断创新、不断成长</p></div><div style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:18px;border-radius:12px;"><p class="tc-green tc-bold" style="margin:0;font-size:16px;">🙏 凡事感激</p><p class="tc-body" style="margin:8px 0 0 0;font-size:14px;">知恩、感恩、施恩</p></div><div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);padding:18px;border-radius:12px;"><p class="tc-red tc-bold" style="margin:0;font-size:16px;">🤝 同心同行</p><p class="tc-body" style="margin:8px 0 0 0;font-size:14px;">群策群力，共享共赢</p></div><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p class="tc-blue tc-bold" style="margin:0;font-size:16px;">✨ 做光做盐</p><p class="tc-body" style="margin:8px 0 0 0;font-size:14px;">生命影响生命</p></div><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:18px;border-radius:12px;"><p class="tc-bold" style="margin:0;font-size:16px;color:#f97316;">🌟 JUICE</p><p class="tc-body" style="margin:8px 0 0 0;font-size:14px;">让我们一起创造美好生活。</p></div></div><h2 id="📌-我们能够改变" tabindex="-1">📌 我们能够改变 <a class="header-anchor" href="#📌-我们能够改变" aria-label="Permalink to &quot;📌 我们能够改变&quot;">​</a></h2><p>  我们必须相信，目前我们拥有的，不论顺境逆境，都是对我们最好的安排。若能如此，我们才能在顺境中感恩，在逆境中依旧心存喜悦。</p><div style="display:flex;flex-direction:column;gap:12px;margin:15px 0;"><div style="display:flex;align-items:center;gap:15px;"><div class="tc-blue" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);width:40px;height:40px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;">1</div><div style="flex:1;background:rgba(102,126,234,0.08);padding:12px 15px;border-radius:10px;border-left:4px solid #667eea;"><p class="tc-body" style="margin:0;font-size:15px;">人生之事，没有十全十美的。</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div class="tc-green" style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);width:40px;height:40px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;">2</div><div style="flex:1;background:rgba(102,126,234,0.08);padding:12px 15px;border-radius:10px;border-left:4px solid #22c55e;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>心若改变</strong>，我的态度跟着改变。</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);color:#f97316;width:40px;height:40px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;">3</div><div style="flex:1;background:rgba(102,126,234,0.08);padding:12px 15px;border-radius:10px;border-left:4px solid #f97316;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>态度改变</strong>，我的习惯跟着改变。</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div class="tc-blue" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);width:40px;height:40px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;">4</div><div style="flex:1;background:rgba(102,126,234,0.08);padding:12px 15px;border-radius:10px;border-left:4px solid #667eea;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>习惯改变</strong>，我的性格跟着改变。</p></div></div><div style="display:flex;align-items:center;gap:15px;"><div class="tc-green" style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);width:40px;height:40px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;">5</div><div style="flex:1;background:rgba(102,126,234,0.08);padding:12px 15px;border-radius:10px;border-left:4px solid #22c55e;"><p class="tc-body" style="margin:0;font-size:15px;"><strong>性格改变</strong>，我的人生跟着改变。</p></div></div></div><h2 id="📌-凡事感激" tabindex="-1">📌 凡事感激 <a class="header-anchor" href="#📌-凡事感激" aria-label="Permalink to &quot;📌 凡事感激&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:10px;margin:15px 0;"><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:12px 15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>🙏 感激伤害我的人</strong></p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">因为他磨练了我的心志。</p></div><div style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:12px 15px;border-radius:10px;"><p class="tc-green" style="margin:0;font-size:14px;"><strong>🙏 感激欺骗我的人</strong></p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">因为他增进了我的智慧。</p></div><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:12px 15px;border-radius:10px;"><p style="margin:0;font-size:14px;color:#f97316;"><strong>🙏 感激中伤我的人</strong></p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">因为他砥砺了我的人格。</p></div><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:12px 15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>🙏 感激鞭策我的人</strong></p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">因为他激发了我的斗志。</p></div><div style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:12px 15px;border-radius:10px;"><p class="tc-green" style="margin:0;font-size:14px;"><strong>🙏 感激遗弃我的人</strong></p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">因为他教导了我要独立。</p></div><div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);padding:12px 15px;border-radius:10px;"><p class="tc-red" style="margin:0;font-size:14px;"><strong>🙏 感激绊倒我的人</strong></p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">因为他强化了我的双腿。</p></div><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:12px 15px;border-radius:10px;"><p style="margin:0;font-size:14px;color:#f97316;"><strong>🙏 感激斥责我的人</strong></p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">因为他提醒了我的缺点。</p></div><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:12px 15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>🙏 感激所有使我坚强的人</strong></p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">感谢每一个帮助我成长的人。</p></div></div><h2 id="📌-尽己所能" tabindex="-1">📌 尽己所能 <a class="header-anchor" href="#📌-尽己所能" aria-label="Permalink to &quot;📌 尽己所能&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px;margin:15px 0;"><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>❌ 我不能</strong></p><p class="tc-body tc-sm" style="margin:8px 0 5px 0;">决定生命的长度</p><p class="tc-green" style="margin:0;font-size:14px;"><strong>✅ 但我可以</strong></p><p class="tc-body" style="margin:5px 0 0 0;font-size:14px;">控制它的宽度</p></div><div style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>❌ 我不能</strong></p><p class="tc-body tc-sm" style="margin:8px 0 5px 0;">左右天气</p><p class="tc-green" style="margin:0;font-size:14px;"><strong>✅ 但我可以</strong></p><p class="tc-body" style="margin:5px 0 0 0;font-size:14px;">改变心情</p></div><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>❌ 我不能</strong></p><p class="tc-body tc-sm" style="margin:8px 0 5px 0;">改变容貌</p><p class="tc-green" style="margin:0;font-size:14px;"><strong>✅ 但我可以</strong></p><p class="tc-body" style="margin:5px 0 0 0;font-size:14px;">改变笑容</p></div><div style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>❌ 我不能</strong></p><p class="tc-body tc-sm" style="margin:8px 0 5px 0;">控制他人</p><p class="tc-green" style="margin:0;font-size:14px;"><strong>✅ 但我可以</strong></p><p class="tc-body" style="margin:5px 0 0 0;font-size:14px;">把握自己</p></div><div style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>❌ 我不能</strong></p><p class="tc-body tc-sm" style="margin:8px 0 5px 0;">预知明天</p><p class="tc-green" style="margin:0;font-size:14px;"><strong>✅ 但我可以</strong></p><p class="tc-body" style="margin:5px 0 0 0;font-size:14px;">利用今天</p></div><div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);padding:15px;border-radius:10px;"><p class="tc-blue" style="margin:0;font-size:14px;"><strong>❌ 我不能</strong></p><p class="tc-body tc-sm" style="margin:8px 0 5px 0;">样样顺利</p><p class="tc-green" style="margin:0;font-size:14px;"><strong>✅ 但我可以</strong></p><p class="tc-body" style="margin:5px 0 0 0;font-size:14px;">事事尽力</p></div></div>',19))])}const z=t(g,[["render",c]]);export{v as __pageData,z as default};
